INSERT INTO `settings` (`id`, `key`, `value`, `type`, `group`, `description`, `is_public`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'company_name', '\"Ipd-OPD System\"', 'string', 'company', 'Official name of the hospital', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(2, 'company_description', '\"Ipd-OPD System is a leading healthcare provider committed to delivering exceptional medical care with compassion, innovation, and excellence. Our dedicated team of healthcare professionals works tirelessly to ensure the well-being of our patients and community.\"', 'text', 'company', 'Brief description of the hospital', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(3, 'company_mission', '\"To provide comprehensive, compassionate healthcare services that improve the health and well-being of our patients and community through excellence in medical care, education, and research.\"', 'text', 'company', 'Hospital mission statement', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(4, 'company_vision', '\"To be the leading healthcare provider in the region, recognized for our commitment to patient-centered care, medical innovation, and community health improvement.\"', 'text', 'company', 'Hospital vision statement', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(5, 'company_values', '\"Compassion, Excellence, Integrity, Innovation, and Community Service guide everything we do in our commitment to patient care and medical advancement.\"', 'text', 'company', 'Hospital core values', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(6, 'company_address', '\"123 Medical Center Drive, Springfield, IL 62701, United States\"', 'text', 'company', 'Complete hospital address', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(7, 'company_phone', '\"+1 (555) 123-4567\"', 'string', 'company', 'Main hospital phone number', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(8, 'company_emergency_phone', '\"+1 (555) 911-0000\"', 'string', 'company', 'Emergency contact number', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(9, 'company_email', '\"info@springfieldgeneral.com\"', 'string', 'company', 'Main hospital email address', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(10, 'company_founded_year', '\"1998\"', 'string', 'company', 'Year the hospital was founded', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
