(16, 'company_logo_small', '\"storage/company/logo-small.png\"', 'image', 'company', 'Small / compact logo for invoice footer or POS receipts', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(17, 'company_favicon', '\"storage/company/favicon.ico\"', 'image', 'company', 'Browser tab favicon (16x16 or 32x32 .ico/.png)', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(18, 'company_login_banner', '\"storage/company/login-banner.png\"', 'image', 'company', 'Background image / banner shown on the login screen', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(19, 'company_website', '\"https://example-hospital.com\"', 'string', 'company', 'Public website URL', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(20, 'company_tax_id', '\"TAX-123456789\"', 'string', 'company', 'Company tax ID for invoices', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(21, 'company_vat', '\"VAT-987654321\"', 'string', 'company', 'Company VAT registration for invoices', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(22, 'company_registration_number', '\"REG-000001\"', 'string', 'company', 'Company registration number', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(23, 'company_footer_text', '\"Thank you for choosing our services. Payments are non-refundable.\"', 'text', 'company', 'Footer text to show on printed documents like invoices and receipts', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(24, 'company_ceo_name', '\"Dr. Sarah Johnson\"', 'string', 'company', 'Chief Executive Officer name', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(25, 'company_ceo_bio', '\"Dr. Sarah Johnson brings over 20 years of healthcare leadership experience, specializing in hospital administration and patient care innovation.\"', 'text', 'company', 'Brief biography of the CEO', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(26, 'company_cmo_name', '\"Dr. Michael Chen\"', 'string', 'company', 'Chief Medical Officer name', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(27, 'company_cmo_bio', '\"Dr. Michael Chen oversees medical operations and quality assurance, ensuring the highest standards of patient care across all departments.\"', 'text', 'company', 'Brief biography of the CMO', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(28, 'company_cno_name', '\"Ms. Emily Rodriguez\"', 'string', 'company', 'Chief Nursing Officer name', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(29, 'company_cno_bio', '\"Ms. Emily Rodriguez leads our nursing staff and patient care services, maintaining excellence in nursing practice and patient safety.\"', 'text', 'company', 'Brief biography of the CNO', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(30, 'company_history_foundation', '\"Our hospital was founded with a vision to provide accessible, high-quality healthcare to our community. Starting as a small clinic, we have grown into a comprehensive medical center.\"', 'text', 'company', 'History of the hospital foundation', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(31, 'company_history_expansion', '\"Major expansion phase with the addition of new departments, advanced medical equipment, and increased bed capacity to better serve our growing patient population.\"', 'text', 'company', 'History of hospital expansion', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(32, 'company_history_innovation', '\"Embraced cutting-edge medical technology and established partnerships with leading research institutions to bring the latest treatments and procedures to our patients.\"', 'text', 'company', 'History of medical innovation', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(33, 'company_history_today', '\"Today, we continue our commitment to excellence, serving thousands of patients annually with compassion, innovation, and the highest standards of medical care.\"', 'text', 'company', 'Current status and achievements', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(34, 'business_hours_emergency_weekdays', '\"24/7\"', 'string', 'business_hours', 'Emergency services hours on weekdays', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(35, 'business_hours_emergency_weekends', '\"24/7\"', 'string', 'business_hours', 'Emergency services hours on weekends', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(36, 'business_hours_opd_weekdays', '\"8:00 AM - 8:00 PM\"', 'string', 'business_hours', 'Outpatient department hours on weekdays', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(37, 'business_hours_opd_weekends', '\"9:00 AM - 5:00 PM\"', 'string', 'business_hours', 'Outpatient department hours on weekends', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(38, 'business_hours_pharmacy_weekdays', '\"8:00 AM - 10:00 PM\"', 'string', 'business_hours', 'Pharmacy hours on weekdays', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
(39, 'business_hours_pharmacy_weekends', '\"9:00 AM - 8:00 PM\"', 'string', 'business_hours', 'Pharmacy hours on weekends', 1, 1, '2026-05-19 11:54:12', '2026-05-19 11:54:12'),
